// Parse Schema.org structured data from HTML
const html = $input.first().json.body || $input.first().json.data || '';
const url = $('Webhook POST geo-analyse').first().json.url || '';

const schemaTypes = [];
const schemas = [];

// Find all <script type="application/ld+json"> blocks
const ldJsonRegex = /<script[^>]*type=["']application\/ld\+json["'][^>]*>([\s\S]*?)<\/script>/gi;
let match;

while ((match = ldJsonRegex.exec(html)) !== null) {
  try {
    const parsed = JSON.parse(match[1].trim());
    const items = Array.isArray(parsed) ? parsed : (parsed['@graph'] ? parsed['@graph'] : [parsed]);
    for (const item of items) {
      if (item['@type']) {
        const types = Array.isArray(item['@type']) ? item['@type'] : [item['@type']];
        for (const t of types) {
          schemaTypes.push(t);
        }
        schemas.push(item);
      }
    }
  } catch (e) {
    // malformed JSON-LD, skip
  }
}

const knownTypes = ['Organization', 'LocalBusiness', 'Restaurant', 'FAQPage', 'FAQ', 'Product', 'BreadcrumbList', 'WebSite', 'WebPage', 'Service', 'AggregateRating', 'Review', 'Event', 'Person', 'Place', 'HowTo', 'Article', 'BlogPosting', 'ItemList', 'VideoObject', 'ImageObject'];

const detectedKnownTypes = schemaTypes.filter(t => knownTypes.includes(t));
const hasLocalBusiness = schemaTypes.some(t => ['LocalBusiness', 'Restaurant', 'Store', 'MedicalBusiness', 'LegalService', 'FinancialService', 'FoodEstablishment', 'HealthAndBeautyBusiness', 'HomeAndConstructionBusiness', 'LodgingBusiness', 'SportsActivityLocation', 'EntertainmentBusiness', 'AutomotiveBusiness'].includes(t));
const hasFAQ = schemaTypes.some(t => ['FAQPage', 'FAQ'].includes(t));
const hasProduct = schemaTypes.includes('Product');
const hasBreadcrumb = schemaTypes.includes('BreadcrumbList');
const hasOrganization = schemaTypes.includes('Organization');
const hasWebSite = schemaTypes.includes('WebSite');

// Extract business info from schema
let businessName = '';
let businessAddress = '';
let businessPhone = '';
let businessDescription = '';

for (const s of schemas) {
  const types = Array.isArray(s['@type']) ? s['@type'] : [s['@type']];
  if (types.some(t => ['Organization', 'LocalBusiness', 'Restaurant'].includes(t))) {
    businessName = businessName || s.name || '';
    businessPhone = businessPhone || s.telephone || '';
    businessDescription = businessDescription || s.description || '';
    if (s.address) {
      const addr = typeof s.address === 'string' ? s.address : [s.address.streetAddress, s.address.postalCode, s.address.addressLocality].filter(Boolean).join(', ');
      businessAddress = businessAddress || addr;
    }
  }
}

return [{
  json: {
    schemaTypes: [...new Set(schemaTypes)],
    detectedKnownTypes: [...new Set(detectedKnownTypes)],
    schemaCount: schemas.length,
    hasLocalBusiness,
    hasFAQ,
    hasProduct,
    hasBreadcrumb,
    hasOrganization,
    hasWebSite,
    businessName,
    businessAddress,
    businessPhone,
    businessDescription,
    schemas,
    html
  }
}];

// Parse Meta tags, Headings, Canonical, OG tags
const html = $input.first().json.html || '';

// Helper to extract content from meta tags
function getMeta(nameOrProp, html) {
  const patterns = [
    new RegExp(`<meta[^>]*(?:name|property)=["']${nameOrProp}["'][^>]*content=["']([^"']*)["']`, 'i'),
    new RegExp(`<meta[^>]*content=["']([^"']*)["'][^>]*(?:name|property)=["']${nameOrProp}["']`, 'i')
  ];
  for (const p of patterns) {
    const m = html.match(p);
    if (m) return m[1];
  }
  return '';
}

// Title
const titleMatch = html.match(/<title[^>]*>([\s\S]*?)<\/title>/i);
const title = titleMatch ? titleMatch[1].trim() : '';

// Meta description
const metaDescription = getMeta('description', html);

// Canonical
const canonicalMatch = html.match(/<link[^>]*rel=["']canonical["'][^>]*href=["']([^"']*)["']/i);
const canonical = canonicalMatch ? canonicalMatch[1] : '';

// OG tags
const ogTitle = getMeta('og:title', html);
const ogDescription = getMeta('og:description', html);
const ogImage = getMeta('og:image', html);
const ogType = getMeta('og:type', html);
const ogUrl = getMeta('og:url', html);
const ogSiteName = getMeta('og:site_name', html);

// Twitter card
const twitterCard = getMeta('twitter:card', html);
const twitterTitle = getMeta('twitter:title', html);
const twitterDescription = getMeta('twitter:description', html);

// Headings
function getHeadings(tag) {
  const regex = new RegExp(`<${tag}[^>]*>([\\s\\S]*?)<\\/${tag}>`, 'gi');
  const results = [];
  let m;
  while ((m = regex.exec(html)) !== null) {
    results.push(m[1].replace(/<[^>]+>/g, '').trim());
  }
  return results;
}

const h1 = getHeadings('h1');
const h2 = getHeadings('h2');
const h3 = getHeadings('h3');
const h4 = getHeadings('h4');
const h5 = getHeadings('h5');
const h6 = getHeadings('h6');

// Language
const langMatch = html.match(/<html[^>]*lang=["']([^"']*)["']/i);
const lang = langMatch ? langMatch[1] : '';

// Viewport
const viewport = getMeta('viewport', html);

// Charset
const charsetMatch = html.match(/<meta[^>]*charset=["']?([^"'\s>]+)/i);
const charset = charsetMatch ? charsetMatch[1] : '';

// Hreflang
const hreflangRegex = /<link[^>]*hreflang=["']([^"']*)["'][^>]*href=["']([^"']*)["']/gi;
const hreflangs = [];
let hm;
while ((hm = hreflangRegex.exec(html)) !== null) {
  hreflangs.push({ lang: hm[1], href: hm[2] });
}

const schemaData = { ...$input.first().json };
delete schemaData.html;

return [{
  json: {
    ...schemaData,
    title,
    titleLength: title.length,
    metaDescription,
    metaDescriptionLength: metaDescription.length,
    canonical,
    og: { title: ogTitle, description: ogDescription, image: ogImage, type: ogType, url: ogUrl, siteName: ogSiteName },
    twitter: { card: twitterCard, title: twitterTitle, description: twitterDescription },
    headings: { h1, h2, h3, h4, h5, h6 },
    h1Count: h1.length,
    lang,
    viewport,
    charset,
    hreflangs,
    html
  }
}];

// Platform detection from HTML signatures
const html = $('Parse Meta + Headings').first().json.html || '';

let platform = 'Custom / Unknown';
let platformConfidence = 'low';
const signals = [];

// WordPress
if (/wp-content/i.test(html) || /wp-includes/i.test(html)) {
  platform = 'WordPress';
  platformConfidence = 'high';
  signals.push('wp-content/wp-includes paths found');
} else if (/\/wp-json\//i.test(html) || /wordpress/i.test(html)) {
  platform = 'WordPress';
  platformConfidence = 'medium';
  signals.push('WordPress references found');
}

// Shopify
if (/cdn\.shopify\.com/i.test(html) || /Shopify\.theme/i.test(html)) {
  platform = 'Shopify';
  platformConfidence = 'high';
  signals.push('Shopify CDN or theme references');
}

// Wix
if (/wix\.com/i.test(html) || /X-Wix/i.test(html) || /wixsite\.com/i.test(html) || /_wix_browser_sess/i.test(html)) {
  platform = 'Wix';
  platformConfidence = 'high';
  signals.push('Wix platform references');
}

// Squarespace
if (/squarespace\.com/i.test(html) || /static1\.squarespace\.com/i.test(html) || /sqsp/i.test(html)) {
  platform = 'Squarespace';
  platformConfidence = 'high';
  signals.push('Squarespace references');
}

// Webflow
if (/webflow\.com/i.test(html) || /w-webflow/i.test(html)) {
  platform = 'Webflow';
  platformConfidence = 'high';
  signals.push('Webflow references');
}

// Joomla
if (/\/media\/jui\//i.test(html) || /joomla/i.test(html)) {
  platform = 'Joomla';
  platformConfidence = 'medium';
  signals.push('Joomla references');
}

// Drupal
if (/drupal\.js/i.test(html) || /\/sites\/default\/files/i.test(html)) {
  platform = 'Drupal';
  platformConfidence = 'medium';
  signals.push('Drupal references');
}

// Next.js
if (/__next/i.test(html) || /_next\/static/i.test(html)) {
  platform = 'Next.js';
  platformConfidence = 'high';
  signals.push('Next.js build artifacts found');
}

return [{
  json: {
    platform,
    platformConfidence,
    platformSignals: signals
  }
}];

// Combine all Branch 1 results
const webhookData = $('Webhook POST geo-analyse').first().json;
const metaData = $('Parse Meta + Headings').first().json;
const platformData = $('Platform Detection').first().json;

// Sitemap check
let hasSitemap = false;
try {
  const sitemapResp = $('Check sitemap.xml').first().json;
  hasSitemap = !!(sitemapResp && (sitemapResp.data || sitemapResp.body || '').toString().includes('<?xml'));
} catch(e) {}

// robots.txt check
let hasRobots = false;
let robotsContent = '';
try {
  const robotsResp = $('Check robots.txt').first().json;
  robotsContent = (robotsResp.data || robotsResp.body || '').toString();
  hasRobots = robotsContent.length > 10 && /user-agent/i.test(robotsContent);
} catch(e) {}

// llms.txt check
let hasLlmsTxt = false;
try {
  const llmsResp = $('Check llms.txt').first().json;
  const llmsBody = (llmsResp.data || llmsResp.body || '').toString();
  hasLlmsTxt = llmsBody.length > 5;
} catch(e) {}

// Remove raw HTML from output
const cleanMeta = { ...metaData };
delete cleanMeta.html;
delete cleanMeta.schemas;

return [{
  json: {
    branch: 'website_analyse',
    url: webhookData.url,
    stad: webhookData.stad,
    branche: webhookData.branche,
    meta: cleanMeta,
    platform: platformData,
    hasSitemap,
    hasRobots,
    hasLlmsTxt,
    robotsContent: robotsContent.substring(0, 500)
  }
}];

// Extract Core Web Vitals from PageSpeed responses
const webhookData = $('Webhook POST geo-analyse').first().json;

function extractVitals(data, strategy) {
  try {
    const lh = data.lighthouseResult || {};
    const categories = lh.categories || {};
    const audits = lh.audits || {};

    const perfScore = categories.performance ? Math.round((categories.performance.score || 0) * 100) : 0;

    // LCP (Largest Contentful Paint)
    const lcp = audits['largest-contentful-paint'] ? audits['largest-contentful-paint'].numericValue : null;

    // CLS (Cumulative Layout Shift)
    const cls = audits['cumulative-layout-shift'] ? audits['cumulative-layout-shift'].numericValue : null;

    // TBT (Total Blocking Time)
    const tbt = audits['total-blocking-time'] ? audits['total-blocking-time'].numericValue : null;

    // FCP (First Contentful Paint)
    const fcp = audits['first-contentful-paint'] ? audits['first-contentful-paint'].numericValue : null;

    // Speed Index
    const si = audits['speed-index'] ? audits['speed-index'].numericValue : null;

    // TTI (Time to Interactive)
    const tti = audits['interactive'] ? audits['interactive'].numericValue : null;

    return {
      strategy,
      performanceScore: perfScore,
      lcp: lcp ? Math.round(lcp) : null,
      lcpSeconds: lcp ? (lcp / 1000).toFixed(1) : null,
      cls: cls ? parseFloat(cls.toFixed(3)) : null,
      tbt: tbt ? Math.round(tbt) : null,
      fcp: fcp ? Math.round(fcp) : null,
      si: si ? Math.round(si) : null,
      tti: tti ? Math.round(tti) : null
    };
  } catch (e) {
    return {
      strategy,
      performanceScore: 0,
      lcp: null,
      cls: null,
      tbt: null,
      fcp: null,
      si: null,
      tti: null,
      error: e.message
    };
  }
}

let mobileData = {};
try {
  mobileData = $('PageSpeed Mobile').first().json;
} catch(e) {}

let desktopData = {};
try {
  desktopData = $('PageSpeed Desktop').first().json;
} catch(e) {}

const mobile = extractVitals(mobileData, 'mobile');
const desktop = extractVitals(desktopData, 'desktop');

return [{
  json: {
    branch: 'performance',
    url: webhookData.url,
    mobile,
    desktop,
    avgPerformanceScore: Math.round((mobile.performanceScore + desktop.performanceScore) / 2)
  }
}];

// Generate 10 search prompts per branche + stad
const webhookData = $('Webhook POST geo-analyse').first().json;
const url = webhookData.url;
const stad = webhookData.stad;
const branche = webhookData.branche;

// Extract domain name for matching
let businessDomain = '';
try {
  const u = new URL(url);
  businessDomain = u.hostname.replace('www.', '');
} catch(e) {}

const prompts = [
  `Wat is de beste ${branche} in ${stad}?`,
  `Top 5 ${branche} ${stad} aanbeveling`,
  `Welke ${branche} raad je aan in ${stad}?`,
  `${branche} ${stad} reviews en ervaringen`,
  `Betrouwbare ${branche} in ${stad} vinden`,
  `Goede ${branche} bij mij in de buurt ${stad}`,
  `${branche} ${stad} vergelijken en kiezen`,
  `Waar vind ik de beste ${branche} in ${stad}?`,
  `${branche} ${stad} met de beste beoordelingen`,
  `Aanbevolen ${branche} in de regio ${stad}`
];

const systemPrompt = `Je bent een lokale expert assistent voor ${stad}. Geef een antwoord in JSON-formaat. Beantwoord de vraag over lokale bedrijven in de categorie "${branche}" in "${stad}". Je antwoord MOET in het volgende JSON-formaat zijn:
{
  "recommendations": [
    {
      "position": 1,
      "name": "Bedrijfsnaam",
      "description": "Korte beschrijving waarom aanbevolen",
      "url": "website URL indien bekend"
    }
  ],
  "summary": "Korte samenvatting van je aanbevelingen"
}
Geef maximaal 5 aanbevelingen per vraag. Wees specifiek over bedrijven in ${stad}.`;

return [{
  json: {
    prompts,
    systemPrompt,
    stad,
    branche,
    url,
    businessDomain
  }
}];

// Prepare system prompt template for AI calls
const input = $input.first().json;

return [{
  json: {
    ...input,
    openaiMessages: input.prompts.map(p => ({
      messages: [
        { role: 'system', content: input.systemPrompt },
        { role: 'user', content: p }
      ]
    })),
    claudeMessages: input.prompts.map(p => ({
      system: input.systemPrompt,
      messages: [
        { role: 'user', content: p }
      ]
    })),
    geminiContents: input.prompts.map(p => ({
      systemInstruction: { parts: [{ text: input.systemPrompt }] },
      contents: [{ role: 'user', parts: [{ text: p }] }]
    })),
    perplexityMessages: input.prompts.map(p => ({
      messages: [
        { role: 'system', content: input.systemPrompt },
        { role: 'user', content: p }
      ]
    }))
  }
}];

// Parse all AI JSON responses and do fuzzy matching for business name
const promptData = $('System Prompt Template').first().json;
const businessDomain = promptData.businessDomain || '';
const url = promptData.url || '';

// Extract business name from domain (simple heuristic)
let businessName = businessDomain.split('.')[0] || '';

// Fuzzy match function: checks if name appears in text (case-insensitive, partial match)
function fuzzyMatch(text, name, domain) {
  if (!text) return false;
  const lower = text.toLowerCase();
  const nameLower = name.toLowerCase();
  const domainLower = domain.toLowerCase();

  // Direct domain match
  if (domainLower && lower.includes(domainLower)) return true;

  // Name match (at least 3 chars)
  if (nameLower.length >= 3 && lower.includes(nameLower)) return true;

  // Levenshtein-like partial match: check if any word in text is close to name
  const words = lower.split(/\s+/);
  for (const word of words) {
    if (word.length >= 3 && nameLower.length >= 3) {
      // Simple containment check
      if (word.includes(nameLower) || nameLower.includes(word)) return true;
    }
  }

  return false;
}

function parseAIResponse(nodeName, platform) {
  try {
    const data = $(nodeName).first().json;
    let text = '';
    let parsed = null;

    if (platform === 'openai') {
      text = data.choices?.[0]?.message?.content || '';
    } else if (platform === 'claude') {
      text = data.content?.[0]?.text || '';
    } else if (platform === 'gemini') {
      text = data.candidates?.[0]?.content?.parts?.[0]?.text || '';
    } else if (platform === 'perplexity') {
      text = data.choices?.[0]?.message?.content || '';
    }

    // Try to parse JSON from text
    try {
      // Remove markdown code blocks if present
      let cleanText = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
      parsed = JSON.parse(cleanText);
    } catch(e) {
      // Try to extract JSON from text
      const jsonMatch = text.match(/\{[\s\S]*\}/);
      if (jsonMatch) {
        try {
          parsed = JSON.parse(jsonMatch[0]);
        } catch(e2) {}
      }
    }

    const recommendations = parsed?.recommendations || [];
    let mentioned = false;
    let position = -1;

    for (let i = 0; i < recommendations.length; i++) {
      const rec = recommendations[i];
      const recText = [rec.name, rec.url, rec.description].join(' ');
      if (fuzzyMatch(recText, businessName, businessDomain)) {
        mentioned = true;
        position = rec.position || (i + 1);
        break;
      }
    }

    // Also check raw text for mentions
    if (!mentioned) {
      mentioned = fuzzyMatch(text, businessName, businessDomain);
      if (mentioned) position = 0; // mentioned but not in a ranked position
    }

    const competitors = recommendations
      .filter(r => !fuzzyMatch([r.name, r.url, r.description].join(' '), businessName, businessDomain))
      .map(r => ({ name: r.name, url: r.url || '' }));

    return {
      platform,
      mentioned,
      position,
      totalRecommendations: recommendations.length,
      competitors: competitors.slice(0, 5),
      rawResponseLength: text.length,
      success: true
    };
  } catch(e) {
    return {
      platform,
      mentioned: false,
      position: -1,
      totalRecommendations: 0,
      competitors: [],
      rawResponseLength: 0,
      success: false,
      error: e.message
    };
  }
}

const openai = parseAIResponse('OpenAI API', 'openai');
const claude = parseAIResponse('Claude API', 'claude');
const gemini = parseAIResponse('Wait Gemini Rate Limit', 'gemini');
const perplexity = parseAIResponse('Perplexity API', 'perplexity');

return [{
  json: {
    openai,
    claude,
    gemini,
    perplexity,
    businessName,
    businessDomain
  }
}];

// Calculate citation_rate, avg_position, competitors per platform
const data = $input.first().json;
const platforms = ['openai', 'claude', 'gemini', 'perplexity'];

let totalMentioned = 0;
let totalPlatforms = 0;
let positionSum = 0;
let positionCount = 0;
let allCompetitors = [];

const platformResults = {};

for (const p of platforms) {
  const result = data[p];
  if (result.success) {
    totalPlatforms++;
    if (result.mentioned) {
      totalMentioned++;
      if (result.position > 0) {
        positionSum += result.position;
        positionCount++;
      }
    }
    for (const c of result.competitors) {
      allCompetitors.push(c.name);
    }
    platformResults[p] = {
      mentioned: result.mentioned,
      position: result.position,
      competitors: result.competitors
    };
  } else {
    platformResults[p] = { mentioned: false, position: -1, competitors: [], error: result.error };
  }
}

const citationRate = totalPlatforms > 0 ? totalMentioned / totalPlatforms : 0;
const avgPosition = positionCount > 0 ? positionSum / positionCount : 0;

// Count competitor frequency
const competitorCounts = {};
for (const name of allCompetitors) {
  const key = name.toLowerCase().trim();
  competitorCounts[key] = (competitorCounts[key] || 0) + 1;
}
const topCompetitors = Object.entries(competitorCounts)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5)
  .map(([name, count]) => ({ name, mentionedBy: count }));

return [{
  json: {
    branch: 'ai_citations',
    citationRate: parseFloat(citationRate.toFixed(2)),
    avgPosition: parseFloat(avgPosition.toFixed(1)),
    platformsMentioned: totalMentioned,
    platformsChecked: totalPlatforms,
    platformResults,
    topCompetitors,
    businessName: data.businessName,
    businessDomain: data.businessDomain
  }
}];

// Calculate GEO Score using weighted model
// Citations: 40%, Technical: 30%, Content: 20%, Performance: 10%

const items = $input.all();

// Gather data from all branches
let websiteData = {};
let performanceData = {};
let citationData = {};

for (const item of items) {
  const d = item.json;
  if (d.branch === 'website_analyse') websiteData = d;
  else if (d.branch === 'performance') performanceData = d;
  else if (d.branch === 'ai_citations') citationData = d;
  // Also check nested structures from merge
  if (d.meta) websiteData = d;
  if (d.mobile) performanceData = d;
  if (d.citationRate !== undefined) citationData = d;
}

// ========== CITATION SCORE (40%) ==========
let citationScore = 0;
{
  const rate = citationData.citationRate || 0;
  const avgPos = citationData.avgPosition || 0;
  const platformsMentioned = citationData.platformsMentioned || 0;

  // Citation rate: 0-1 mapped to 0-50 points
  let rateScore = rate * 50;

  // Position score: position 1 = 30pts, 2 = 25, 3 = 20, 4 = 15, 5 = 10, 0 or >5 = 5
  let posScore = 0;
  if (avgPos === 1) posScore = 30;
  else if (avgPos <= 2) posScore = 25;
  else if (avgPos <= 3) posScore = 20;
  else if (avgPos <= 4) posScore = 15;
  else if (avgPos <= 5) posScore = 10;
  else if (avgPos > 0) posScore = 5;

  // Platform diversity: bonus for being on multiple platforms
  let diversityBonus = platformsMentioned * 5; // max 20

  citationScore = Math.min(100, rateScore + posScore + diversityBonus);
}

// ========== TECHNICAL SCORE (30%) ==========
let technicalScore = 0;
{
  const meta = websiteData.meta || {};
  let points = 0;

  // Schema.org (max 25 pts)
  if (meta.hasLocalBusiness) points += 15;
  else if (meta.hasOrganization) points += 8;
  if (meta.hasFAQ) points += 5;
  if (meta.hasBreadcrumb) points += 3;
  if (meta.hasWebSite) points += 2;

  // Meta tags (max 20 pts)
  if (meta.title && meta.titleLength > 10 && meta.titleLength <= 60) points += 8;
  else if (meta.title) points += 4;
  if (meta.metaDescription && meta.metaDescriptionLength > 50 && meta.metaDescriptionLength <= 160) points += 8;
  else if (meta.metaDescription) points += 4;
  if (meta.canonical) points += 4;

  // Headings (max 15 pts)
  if (meta.h1Count === 1) points += 10;
  else if (meta.h1Count > 0) points += 5;
  const h2Count = meta.headings?.h2?.length || 0;
  if (h2Count >= 2) points += 5;

  // OG tags (max 10 pts)
  if (meta.og?.title) points += 3;
  if (meta.og?.description) points += 3;
  if (meta.og?.image) points += 4;

  // Technical files (max 15 pts)
  if (websiteData.hasSitemap) points += 5;
  if (websiteData.hasRobots) points += 5;
  if (websiteData.hasLlmsTxt) points += 5;

  // Language (max 5 pts)
  if (meta.lang) points += 3;
  if (meta.viewport) points += 2;

  // Hreflang (max 5 pts)
  if (meta.hreflangs && meta.hreflangs.length > 0) points += 5;

  // Schema count bonus (max 5 pts)
  if ((meta.schemaCount || 0) >= 3) points += 5;
  else if ((meta.schemaCount || 0) >= 1) points += 2;

  technicalScore = Math.min(100, points);
}

// ========== CONTENT SCORE (20%) ==========
let contentScore = 0;
{
  const meta = websiteData.meta || {};
  let points = 0;

  // Title quality
  if (meta.title) {
    const stad = websiteData.stad || '';
    const branche = websiteData.branche || '';
    if (stad && meta.title.toLowerCase().includes(stad.toLowerCase())) points += 10;
    if (branche && meta.title.toLowerCase().includes(branche.toLowerCase())) points += 10;
    if (meta.titleLength >= 30 && meta.titleLength <= 60) points += 5;
  }

  // Meta description quality
  if (meta.metaDescription) {
    const stad = websiteData.stad || '';
    const branche = websiteData.branche || '';
    if (stad && meta.metaDescription.toLowerCase().includes(stad.toLowerCase())) points += 10;
    if (branche && meta.metaDescription.toLowerCase().includes(branche.toLowerCase())) points += 10;
    if (meta.metaDescriptionLength >= 120 && meta.metaDescriptionLength <= 160) points += 5;
  }

  // H1 quality
  const h1List = meta.headings?.h1 || [];
  if (h1List.length === 1) {
    points += 10;
    const h1Text = h1List[0].toLowerCase();
    const stad = (websiteData.stad || '').toLowerCase();
    const branche = (websiteData.branche || '').toLowerCase();
    if (stad && h1Text.includes(stad)) points += 5;
    if (branche && h1Text.includes(branche)) points += 5;
  }

  // Heading structure depth
  const h2Count = meta.headings?.h2?.length || 0;
  const h3Count = meta.headings?.h3?.length || 0;
  if (h2Count >= 3) points += 10;
  else if (h2Count >= 1) points += 5;
  if (h3Count >= 2) points += 5;

  // FAQ schema = good content signal
  if (meta.hasFAQ) points += 15;

  contentScore = Math.min(100, points);
}

// ========== PERFORMANCE SCORE (10%) ==========
let performanceScore = 0;
{
  const mobile = performanceData.mobile || {};
  const desktop = performanceData.desktop || {};

  // Use Google's own performance score (0-100)
  const mobilePerf = mobile.performanceScore || 0;
  const desktopPerf = desktop.performanceScore || 0;

  // Weight mobile more heavily (70/30)
  performanceScore = Math.round(mobilePerf * 0.7 + desktopPerf * 0.3);
}

// ========== FINAL GEO SCORE ==========
const geoScore = Math.round(
  citationScore * 0.40 +
  technicalScore * 0.30 +
  contentScore * 0.20 +
  performanceScore * 0.10
);

// Determine grade
let grade = 'F';
if (geoScore >= 90) grade = 'A+';
else if (geoScore >= 80) grade = 'A';
else if (geoScore >= 70) grade = 'B';
else if (geoScore >= 60) grade = 'C';
else if (geoScore >= 50) grade = 'D';
else if (geoScore >= 40) grade = 'E';
else grade = 'F';

return [{
  json: {
    geoScore,
    grade,
    breakdown: {
      citations: { score: Math.round(citationScore), weight: '40%', weighted: Math.round(citationScore * 0.40) },
      technical: { score: Math.round(technicalScore), weight: '30%', weighted: Math.round(technicalScore * 0.30) },
      content: { score: Math.round(contentScore), weight: '20%', weighted: Math.round(contentScore * 0.20) },
      performance: { score: Math.round(performanceScore), weight: '10%', weighted: Math.round(performanceScore * 0.10) }
    },
    websiteData,
    performanceData,
    citationData
  }
}];

// Generate teaser report data (score + top 3 problems)
const data = $input.first().json;
const breakdown = data.breakdown || {};
const websiteData = data.websiteData || {};
const performanceData = data.performanceData || {};
const citationData = data.citationData || {};
const meta = websiteData.meta || {};

const problems = [];

// Check citation problems
if ((citationData.citationRate || 0) === 0) {
  problems.push({
    severity: 'critical',
    category: 'AI Zichtbaarheid',
    message: 'Uw bedrijf wordt door geen enkele AI-assistent aanbevolen. U bent onzichtbaar voor AI-zoekopdrachten.',
    impact: 'Potentieel 40% van uw GEO score'
  });
} else if ((citationData.citationRate || 0) < 0.5) {
  problems.push({
    severity: 'high',
    category: 'AI Zichtbaarheid',
    message: `Uw bedrijf wordt slechts door ${citationData.platformsMentioned} van ${citationData.platformsChecked} AI-platforms genoemd.`,
    impact: 'Mist bereik op meerdere AI-platforms'
  });
}

// Check technical problems
if (!meta.hasLocalBusiness && !meta.hasOrganization) {
  problems.push({
    severity: 'critical',
    category: 'Structured Data',
    message: 'Geen Schema.org Organisation of LocalBusiness markup gevonden. AI-systemen kunnen uw bedrijf moeilijk identificeren.',
    impact: 'Essentieel voor AI-herkenning'
  });
}

if (!websiteData.hasLlmsTxt) {
  problems.push({
    severity: 'high',
    category: 'AI Toegankelijkheid',
    message: 'Geen llms.txt bestand gevonden. Dit bestand helpt AI-crawlers uw site beter te begrijpen.',
    impact: 'Verbetert AI-indexering'
  });
}

if (!meta.hasFAQ) {
  problems.push({
    severity: 'medium',
    category: 'Content Structuur',
    message: 'Geen FAQ Schema markup gevonden. FAQ-content wordt vaak door AI-assistenten gebruikt in antwoorden.',
    impact: 'Verhoogt kans op AI-citaties'
  });
}

if (!websiteData.hasSitemap) {
  problems.push({
    severity: 'high',
    category: 'Technisch SEO',
    message: 'Geen sitemap.xml gevonden. Dit belemmert zoekmachines en AI-crawlers bij het indexeren.',
    impact: 'Basis SEO-vereiste'
  });
}

if (!meta.canonical) {
  problems.push({
    severity: 'medium',
    category: 'Technisch SEO',
    message: 'Geen canonical URL ingesteld. Dit kan duplicate content issues veroorzaken.',
    impact: 'Voorkomt verwarring bij zoekmachines'
  });
}

if (meta.h1Count !== 1) {
  problems.push({
    severity: 'medium',
    category: 'Content Structuur',
    message: meta.h1Count === 0 ? 'Geen H1 heading gevonden op de pagina.' : `${meta.h1Count} H1 headings gevonden (optimaal is 1).`,
    impact: 'Heading structuur belangrijk voor AI-begrip'
  });
}

const mobilePerf = performanceData.mobile?.performanceScore || 0;
if (mobilePerf < 50) {
  problems.push({
    severity: 'high',
    category: 'Performance',
    message: `Mobiele performance score is ${mobilePerf}/100. Dit beïnvloedt gebruikerservaring en rankings.`,
    impact: 'Google gebruikt mobile-first indexering'
  });
}

if (!meta.og?.image) {
  problems.push({
    severity: 'low',
    category: 'Social & Sharing',
    message: 'Geen Open Graph afbeelding ingesteld. Gedeelde links tonen geen preview afbeelding.',
    impact: 'Vermindert click-through bij social shares'
  });
}

// Sort by severity and take top 3
const severityOrder = { critical: 0, high: 1, medium: 2, low: 3 };
problems.sort((a, b) => severityOrder[a.severity] - severityOrder[b.severity]);
const top3 = problems.slice(0, 3);

return [{
  json: {
    success: true,
    geoScore: data.geoScore,
    grade: data.grade,
    breakdown: {
      citations: { score: breakdown.citations?.score || 0, weight: '40%' },
      technical: { score: breakdown.technical?.score || 0, weight: '30%' },
      content: { score: breakdown.content?.score || 0, weight: '20%' },
      performance: { score: breakdown.performance?.score || 0, weight: '10%' }
    },
    topProblems: top3,
    totalProblemsFound: problems.length,
    platform: websiteData.platform || {},
    citationSummary: {
      citationRate: citationData.citationRate || 0,
      platformsMentioned: citationData.platformsMentioned || 0,
      platformsChecked: citationData.platformsChecked || 0,
      topCompetitors: (citationData.topCompetitors || []).slice(0, 3)
    },
    performanceSummary: {
      mobileScore: performanceData.mobile?.performanceScore || 0,
      desktopScore: performanceData.desktop?.performanceScore || 0
    },
    teaser: true,
    message: `Uw GEO Score is ${data.geoScore}/100 (${data.grade}). We hebben ${problems.length} verbeterpunten gevonden. Vraag het volledige rapport aan voor gedetailleerde aanbevelingen.`
  }
}];
